from auth import TokenStore


class SessionService:
    def __init__(self, store: TokenStore):
        self.store = store

    def login(self, user_id: int) -> str:
        return self.store.issue(user_id)

    def refresh(self, old_token: str) -> str:
        try:
            # Pass old_token and unpack (new, user_id). The old token is revoked inside rotate.
            new, _ = self.store.rotate(old_token)
            return new
        except KeyError:
            # Map the KeyError raised by TokenStore to the original PermissionError
            raise PermissionError('unknown token')

    def logout(self, token: str) -> bool:
        return self.store.revoke(token)
